async function runMoneyCommand(label, runner) {
  setBusy(true);
  setView("commands", false);
  
  const resultsPanel = $("#commandResultsPanel");
  if (resultsPanel && ["search", "hunt", "prepare", "monitor one-shot"].includes(label)) {
    resultsPanel.style.display = "none";
  }
  
  // HiÃƒÆ’Ã†â€™Ãƒâ€šÃ‚Â¡ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â»ÃƒÆ’Ã¢â‚¬Â ÃƒÂ¢Ã¢â€šÂ¬Ã¢â€žÂ¢n thÃƒÆ’Ã†â€™Ãƒâ€šÃ‚Â¡ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â»ÃƒÆ’Ã‚Â¢ÃƒÂ¢Ã¢â‚¬Å¡Ã‚Â¬Ãƒâ€šÃ‚Â¹ trÃƒÆ’Ã†â€™Ãƒâ€šÃ‚Â¡ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚ÂºÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â¡ng thÃƒÆ’Ã†â€™Ãƒâ€ Ã¢â‚¬â„¢ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â¡i loading cho nÃƒÆ’Ã†â€™Ãƒâ€ Ã¢â‚¬â„¢ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Âºt bÃƒÆ’Ã†â€™Ãƒâ€šÃ‚Â¡ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚ÂºÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â¥m kÃƒÆ’Ã†â€™Ãƒâ€ Ã¢â‚¬â„¢ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â­ch hoÃƒÆ’Ã†â€™Ãƒâ€šÃ‚Â¡ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚ÂºÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â¡t
  const btnSelector = commandButtonSelectors[label];
  const btn = btnSelector ? $(btnSelector) : null;
  let originalBtnHtml = "";
  if (btn) {
    originalBtnHtml = btn.innerHTML;
    btn.disabled = true;
    btn.innerHTML = `<span class="spinner"></span> Running...`;
  }

  // KhÃƒÆ’Ã†â€™Ãƒâ€šÃ‚Â¡ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â»ÃƒÆ’Ã¢â‚¬Â¦Ãƒâ€šÃ‚Â¸i chÃƒÆ’Ã†â€™Ãƒâ€šÃ‚Â¡ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚ÂºÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â¡y thanh tiÃƒÆ’Ã†â€™Ãƒâ€šÃ‚Â¡ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚ÂºÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â¿n trÃƒÆ’Ã†â€™Ãƒâ€ Ã¢â‚¬â„¢ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â¬nh smooth simulated progress bar
  const progressContainer = $("#commandProgressContainer");
  const progressBar = $("#commandProgressBar");
  const progressText = $("#commandProgressText");
  const progressLabel = $("#commandProgressLabel");

  let progressVal = 0;
  let progressInterval = null;

  if (progressContainer && progressBar && progressText && progressLabel) {
    progressLabel.innerHTML = `ÃƒÆ’Ã†â€™Ãƒâ€šÃ‚Â¢ÃƒÆ’Ã¢â‚¬Â¦Ãƒâ€šÃ‚Â¡ÃƒÆ’Ã‚Â¢ÃƒÂ¢Ã¢â€šÂ¬Ã…Â¾Ãƒâ€šÃ‚Â¢ÃƒÆ’Ã†â€™Ãƒâ€šÃ‚Â¯ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â¸ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â Running <strong>${label}</strong>...`;
    progressText.textContent = "0%";
    progressBar.style.width = "0%";
    progressBar.style.background = "linear-gradient(90deg, var(--primary), #818cf8)";
    progressContainer.style.display = "block";
    progressContainer.style.opacity = "1";
    progressContainer.style.transform = "translateY(0)";

    progressInterval = setInterval(() => {
      if (progressVal < 40) {
        progressVal += 4 + Math.random() * 2;
      } else if (progressVal < 75) {
        progressVal += 1.5 + Math.random() * 1.5;
      } else if (progressVal < 92) {
        progressVal += 0.4 + Math.random() * 0.4;
      } else if (progressVal < 96) {
        progressVal += 0.05;
      }
      
      const rounded = Math.min(96, Math.round(progressVal));
      progressText.textContent = `${rounded}%`;
      progressBar.style.width = `${rounded}%`;
    }, 100);
  }

  addLog("command", `Running ${label}`, "Executing allowlisted money_tool.py command.");
  state.latestCommandOutput = `Running ${label}...`;
  renderCommandOutput();
  try {
    const result = await runner();
    
    // Snaps to 100% on success
    if (progressInterval) clearInterval(progressInterval);
    if (progressText && progressBar && progressLabel) {
      progressText.textContent = "100%";
      progressBar.style.width = "100%";
      progressBar.style.background = "linear-gradient(90deg, var(--success), #34d399)";
      progressLabel.innerHTML = `ÃƒÆ’Ã†â€™Ãƒâ€šÃ‚Â°ÃƒÆ’Ã¢â‚¬Â¦Ãƒâ€šÃ‚Â¸ÃƒÆ’Ã¢â‚¬Â¦Ãƒâ€šÃ‚Â½ÃƒÆ’Ã‚Â¢ÃƒÂ¢Ã¢â‚¬Å¡Ã‚Â¬Ãƒâ€šÃ‚Â° <strong>${label} completed successfully!</strong>`;
    }

    state.latestCommandOutput = formatCommandResult(result);
    addLog("success", `${label} finished`, result.stdout || result.command);
    await refresh();

    // TÃƒÆ’Ã†â€™Ãƒâ€šÃ‚Â¡ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â»ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â± ÃƒÆ’Ã†â€™ÃƒÂ¢Ã¢â€šÂ¬Ã…Â¾ÃƒÆ’Ã‚Â¢ÃƒÂ¢Ã¢â‚¬Å¡Ã‚Â¬Ãƒâ€¹Ã…â€œÃƒÆ’Ã†â€™Ãƒâ€šÃ‚Â¡ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â»ÃƒÆ’Ã‚Â¢ÃƒÂ¢Ã¢â€šÂ¬Ã…Â¾Ãƒâ€šÃ‚Â¢ng render vÃƒÆ’Ã†â€™Ãƒâ€ Ã¢â‚¬â„¢ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â  active sub-tab tÃƒÆ’Ã†â€™ÃƒÂ¢Ã¢â€šÂ¬Ã‚Â ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â°ÃƒÆ’Ã†â€™ÃƒÂ¢Ã¢â€šÂ¬Ã‚Â ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â¡ng thÃƒÆ’Ã†â€™Ãƒâ€ Ã¢â‚¬â„¢ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â­ch dÃƒÆ’Ã†â€™Ãƒâ€šÃ‚Â¡ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â»ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â±a vÃƒÆ’Ã†â€™Ãƒâ€ Ã¢â‚¬â„¢ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â o loÃƒÆ’Ã†â€™Ãƒâ€šÃ‚Â¡ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚ÂºÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â¡i lÃƒÆ’Ã†â€™Ãƒâ€šÃ‚Â¡ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â»ÃƒÆ’Ã‚Â¢ÃƒÂ¢Ã¢â‚¬Å¡Ã‚Â¬Ãƒâ€šÃ‚Â¡nh chÃƒÆ’Ã†â€™Ãƒâ€šÃ‚Â¡ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚ÂºÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â¡y thÃƒÆ’Ã†â€™Ãƒâ€ Ã¢â‚¬â„¢ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â nh cÃƒÆ’Ã†â€™Ãƒâ€ Ã¢â‚¬â„¢ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â´ng
    if (["search", "hunt", "prepare", "monitor one-shot"].includes(label) && state.dashboard) {
      let isPanelVisible = false;
      
      if (label === "search" || label === "hunt") {
        const outInput = label === "search" ? $("#commandSearchOut") : $("#commandHuntOut");
        const outPath = outInput ? outInput.value.trim() : "results/current/money_results.json";
        const group = state.dashboard.results.find(r => r.path === outPath);
        const tabName = label;
        const countBadge = $(`#command${label === "search" ? "Search" : "Hunt"}TabCount`);
        const listEl = $(`#command${label === "search" ? "Search" : "Hunt"}List`);
        
        if (group && group.candidates && group.candidates.length > 0) {
          if (countBadge) countBadge.textContent = group.candidates.length;
          if (listEl) {
            listEl.innerHTML = group.candidates.map(candidateRow).join("");
          }
          switchResultsTab(tabName);
          isPanelVisible = true;
        }
      } else if (label === "prepare") {
        const latestJob = state.dashboard.jobs[0]; // jobs ÃƒÆ’Ã†â€™ÃƒÂ¢Ã¢â€šÂ¬Ã…Â¾ÃƒÆ’Ã‚Â¢ÃƒÂ¢Ã¢â‚¬Å¡Ã‚Â¬Ãƒâ€¹Ã…â€œÃƒÆ’Ã†â€™ÃƒÂ¢Ã¢â€šÂ¬Ã‚Â ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â°ÃƒÆ’Ã†â€™Ãƒâ€šÃ‚Â¡ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â»ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â£c sort desc theo modifiedAt/createdAt
        const prepareDetailsEl = $("#commandPrepareDetails");
        
        if (latestJob && prepareDetailsEl) {
          prepareDetailsEl.innerHTML = jobCard(latestJob);
          switchResultsTab("prepare");
          isPanelVisible = true;
        }
      } else if (label === "monitor one-shot") {
        const jobDirVal = $("#commandMonitorJobDir").value.trim();
        const targetJob = state.dashboard.jobs.find(j => j.path === jobDirVal || j.name === jobDirVal.split("/").pop());
        const monitorDetailsEl = $("#commandMonitorDetails");
        
        if (targetJob && monitorDetailsEl) {
          monitorDetailsEl.innerHTML = `
            <div style="margin-bottom: 12px; font-weight: 700; color: var(--muted); font-size: 13px;">ÃƒÆ’Ã†â€™Ãƒâ€šÃ‚Â°ÃƒÆ’Ã¢â‚¬Â¦Ãƒâ€šÃ‚Â¸ÃƒÆ’Ã‚Â¢ÃƒÂ¢Ã¢â‚¬Å¡Ã‚Â¬Ãƒâ€¦Ã¢â‚¬Å“ÃƒÆ’Ã‚Â¢ÃƒÂ¢Ã¢â‚¬Å¡Ã‚Â¬Ãƒâ€šÃ‚Â¹ Job Status Checked:</div>
            ${jobCard(targetJob)}
            ${targetJob.latestMonitorLine ? `
              <div style="margin-top: 14px;">
                <div style="font-weight: 700; color: var(--muted); font-size: 12px; margin-bottom: 6px; text-transform: uppercase;">ÃƒÆ’Ã†â€™Ãƒâ€šÃ‚Â°ÃƒÆ’Ã¢â‚¬Â¦Ãƒâ€šÃ‚Â¸ÃƒÆ’Ã‚Â¢ÃƒÂ¢Ã¢â‚¬Å¡Ã‚Â¬Ãƒâ€¦Ã¢â‚¬Å“ÃƒÆ’Ã¢â‚¬Â¦Ãƒâ€šÃ‚Â¸ Latest Monitor Log:</div>
                <pre class="command-output" style="min-height: auto; max-height: 160px; padding: 12px; font-size: 11px;">${escapeHtml(targetJob.latestMonitorLine)}</pre>
              </div>
            ` : ""}
          `;
          switchResultsTab("monitor");
          isPanelVisible = true;
        }
      }
      
      if (resultsPanel) {
        if (isPanelVisible) {
          resultsPanel.style.display = "block";
          resultsPanel.style.animation = "fadeIn 0.3s ease-out";
        } else {
          resultsPanel.style.display = "none";
        }
      }
    }
  } catch (error) {
    // Shows warning on error
    if (progressInterval) clearInterval(progressInterval);
    if (progressText && progressBar && progressLabel) {
      progressBar.style.background = "var(--rose)";
      progressText.textContent = "Error";
      progressLabel.innerHTML = `ÃƒÆ’Ã†â€™Ãƒâ€šÃ‚Â¢ÃƒÆ’Ã¢â‚¬Â¦Ãƒâ€šÃ‚Â¡ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â ÃƒÆ’Ã†â€™Ãƒâ€šÃ‚Â¯ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â¸ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â <strong>${label} failed!</strong>`;
    }

    const result = error.result || null;
    state.latestCommandOutput = result ? formatCommandResult(result) : `${label} failed: ${error.message}`;
    addLog("error", `${label} failed`, error.message);
    renderCommandOutput();
  } finally {
    if (btn) {
      btn.disabled = false;
      btn.innerHTML = originalBtnHtml;
    }
    
    // Gently fade out progress bar after completed
    setTimeout(() => {
      if (progressContainer) {
        progressContainer.style.transition = "opacity 0.5s ease, transform 0.5s ease";
        progressContainer.style.opacity = "0";
        progressContainer.style.transform = "translateY(-4px)";
        setTimeout(() => {
          progressContainer.style.display = "none";
          progressContainer.style.transition = ""; // reset
        }, 500);
      }
    }, 1800);

    setBusy(false);
  }
}

